import {MapContainer,TileLayer,Polyline} from "react-leaflet"
import {useEffect,useState} from "react"
import {getRoute} from "../services/api"
import { Marker } from "react-leaflet"

export default function RoutePage(){

const [route,setRoute]=useState([])

useEffect(()=>{
getRoute().then(r=>setRoute(r.data))
},[])

const coords=route.map(r=>[r.Latitude,r.Longitude])

return(
<div>

<h2>Truck Route Optimization</h2>

<MapContainer center={[12.97,77.59]} zoom={11} style={{height:"500px"}}>

<TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"/>

<Polyline
positions={coords}
color="blue"
weight={5}
/>

{route.map((bin)=>(
<Marker
key={bin.Bin_ID}
position={[bin.Latitude, bin.Longitude]}
/>
))}

</MapContainer>
<h3>Truck Route Pickup Order</h3>

<table style={{width:"100%",background:"#1e293b"}}>

<thead>
<tr>
<th>Stop</th>
<th>Bin ID</th>
<th>Area</th>
<th>Waste %</th>
</tr>
</thead>

<tbody>

{route.map((bin,index)=>(

<tr key={bin.Bin_ID}>

<td>{index+1}</td>
<td>{bin.Bin_ID}</td>
<td>{bin.Area}</td>
<td>{bin.Waste_Level}%</td>

</tr>

))}

</tbody>

</table>
</div>
)
}
